#include<bits/stdc++.h>
#define rep(a,b,c) for(register int c=(a);c<=(b);++c)
#define drep(a,b,c) for(register int c=(a);c>=(b);--c)
#define int long long
using namespace std;
inline int read()
{
	int res=0;char ch=getchar();bool flag=0;
	while(ch<'0'||ch>'9')flag^=(ch=='-'),ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();
	return flag ? -res : res ;
}
const int M=5e6+10,LIM=5e6;
int mu[M],pm[M>>2],cpt;bool vs[M];long long ph[M];
inline void Init(int mx=LIM)
{
	vs[1]=1;mu[1]=ph[1]=1;rep(2,mx,i)
	{
		vs[i]?0:(pm[++cpt]=i,mu[i]=-1,ph[i]=i-1);
		for(register int j=1;j<=cpt&&i*pm[j]<=mx;++j)
		{
//			mu[pm[j]*i]=(i%pm[j]==0)?0:-mu[i];
//			ph[pm[j]*i]=ph[i]*(pm[j]-(i%pm[j]==0));
//			vs[pm[j]*i]=1;if(i%pm[j]==0)break;
			vs[pm[j]*i]=1;if(i%pm[j]==0){ph[i*pm[j]]=ph[i]*pm[j];break;}
			mu[pm[j]*i]=-mu[i];ph[pm[j]*i]=ph[i]*(pm[j]-1);
		}
	}
	rep(1,mx,i)mu[i]+=mu[i-1],ph[i]+=ph[i-1];
}
long long sph[M];int N,smu[M];
inline long long Sph(int k){return k<=LIM?ph[k]:sph[N/k];}
inline int Smu(int k){return k<=LIM?mu[k]:smu[N/k];}
inline void Solve(int n,int d=1)
{
	
	if(n<=LIM||sph[d])return;
//	printf("%lld %lld %d\n",n,d,n<=LIM);
	int tmu=1;long long tph=(1ll*n*(n+1))>>1;
	
	for(register long long l=2,r;l<=n;l=r+1)
	{
		r=n/(n/l);Solve(n/l,d*l);
		tmu-=Smu(n/l)*(r-l+1);tph-=Sph(n/l)*(r-l+1);
//		printf("%lld %lld\n",l,r);
	}
	if(d<=LIM)sph[d]=tph,smu[d]=tmu;
}
signed main()
{
	Init();int T=read();while(T--)
	{
		memset(sph,0,sizeof(sph));Solve(N=read());
		printf("%lld %lld\n",Sph(N),Smu(N));
	}
}
